interface Props {
  onOpenFile: (file: string) => void;
  activeFile: string | null;
}

interface FileItem {
  name: string;
  type: "file" | "folder";
  children?: FileItem[];
}

const fileTree: FileItem[] = [
  {
    name: "portfolio",
    type: "folder",
    children: [
      { name: "README.md", type: "file" },
      { name: "about.md", type: "file" },
      { name: "skills.md", type: "file" },
    ],
  },
  {
    name: "projects",
    type: "folder",
    children: [
      { name: "crime-prediction.md", type: "file" },
      { name: "football-analytics.md", type: "file" },
      { name: "yelp-analysis.md", type: "file" },
    ],
  },
  {
    name: "experience",
    type: "folder",
    children: [
      { name: "work-history.md", type: "file" },
      { name: "education.md", type: "file" },
    ],
  },
  { name: "contact.md", type: "file" },
];

// File icon component
function FileIcon({ name }: { name: string }) {
  const ext = name.split(".").pop();
  let color = "text-[#6b6b6b]";
  
  if (ext === "md") color = "text-[#519aba]";
  else if (ext === "css") color = "text-[#56b6c2]";
  else if (ext === "ts" || ext === "tsx") color = "text-[#3178c6]";
  else if (ext === "js" || ext === "jsx") color = "text-[#f1e05a]";

  return (
    <svg className={`w-4 h-4 ${color}`} fill="currentColor" viewBox="0 0 24 24">
      <path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8l-6-6zm-1 2l5 5h-5V4z" />
    </svg>
  );
}

// Folder icon component
function FolderIcon({ open }: { open: boolean }) {
  return (
    <svg className="w-4 h-4 text-[#dcb67a]" fill="currentColor" viewBox="0 0 24 24">
      {open ? (
        <path d="M20 6h-8l-2-2H4a2 2 0 00-2 2v12a2 2 0 002 2h16a2 2 0 002-2V8a2 2 0 00-2-2zm0 12H4V8h16v10z" />
      ) : (
        <path d="M10 4H4a2 2 0 00-2 2v12a2 2 0 002 2h16a2 2 0 002-2V8a2 2 0 00-2-2h-8l-2-2z" />
      )}
    </svg>
  );
}

// Chevron icon
function Chevron({ open }: { open: boolean }) {
  return (
    <svg
      className={`w-3 h-3 text-[#6b6b6b] transition-transform ${open ? "rotate-90" : ""}`}
      fill="none"
      stroke="currentColor"
      viewBox="0 0 24 24"
    >
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
    </svg>
  );
}

interface TreeNodeProps {
  item: FileItem;
  depth: number;
  onOpenFile: (file: string) => void;
  activeFile: string | null;
}

function TreeNode({ item, depth, onOpenFile, activeFile }: TreeNodeProps) {
  const [isOpen, setIsOpen] = useState(true);

  if (item.type === "folder") {
    return (
      <div>
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="flex items-center gap-1 w-full py-0.5 hover:bg-[#2a2a2a] rounded text-sm text-[#e5e5e5]"
          style={{ paddingLeft: `${depth * 12 + 4}px` }}
        >
          <Chevron open={isOpen} />
          <FolderIcon open={isOpen} />
          <span className="ml-1">{item.name}</span>
        </button>
        {isOpen && item.children && (
          <div>
            {item.children.map((child) => (
              <TreeNode
                key={child.name}
                item={child}
                depth={depth + 1}
                onOpenFile={onOpenFile}
                activeFile={activeFile}
              />
            ))}
          </div>
        )}
      </div>
    );
  }

  const isActive = activeFile === item.name;

  return (
    <button
      onClick={() => onOpenFile(item.name)}
      className={`flex items-center gap-1 w-full py-0.5 rounded text-sm ${
        isActive
          ? "bg-[#37373d] text-white"
          : "text-[#e5e5e5] hover:bg-[#2a2a2a]"
      }`}
      style={{ paddingLeft: `${depth * 12 + 20}px` }}
    >
      <FileIcon name={item.name} />
      <span className="ml-1">{item.name}</span>
    </button>
  );
}

